    "No matching devices": { "fr": "Aucun appareil correspondant", "de": "Keine passenden Geräte", "zh": "无匹配设备", "hi": "कोई मेल खाते devices नहीं", "es": "No hay dispositivos coincidentes", "ar": "لا توجد أجهزة مطابقة" },
