    'World-exposed ports':    { fr: 'Ports exposés au monde', de: 'Weltweit exponierte Ports', zh: '对外暴露的端口', hi: 'विश्व-उजागर पोर्ट', es: 'Puertos expuestos a Internet', ar: 'المنافذ المكشوفة للإنترنت' },
